const Ad = require('../models/Ad');
const UserInventory = require('../models/UserInventory');
const PatternAsset = require('../models/PatternAsset');
const { redis } = require('../config/redis');

class AdController {
  // 提交广告申请
  static async submitAd(req, res) {
    try {
      const {
        sku_id,
        pattern_id,
        x, y, w, h,
        schedule,
        starts_at,
        ends_at
      } = req.body;
      const userId = req.user.id;
      const allianceId = req.user.alliance_id;

      // 验证必需字段
      if (!sku_id || !pattern_id || x === undefined || y === undefined || !w || !h || !schedule) {
        return res.status(400).json({
          success: false,
          message: '缺少必需字段'
        });
      }

      // 验证用户是否有广告位库存
      const hasAdSlot = await UserInventory.hasEnough(userId, sku_id, 1);
      if (!hasAdSlot) {
        return res.status(400).json({
          success: false,
          message: '广告位库存不足'
        });
      }

      // 验证图案是否存在且已审核
      const pattern = await PatternAsset.getById(pattern_id);
      if (!pattern || !pattern.verified) {
        return res.status(400).json({
          success: false,
          message: '图案不存在或未审核通过'
        });
      }

      // 验证schedule格式
      if (!schedule.interval_sec || !schedule.duration_sec || !schedule.freeze_sec) {
        return res.status(400).json({
          success: false,
          message: 'schedule格式无效'
        });
      }

      // 创建广告
      const ad = await Ad.create({
        sku_id,
        pattern_id,
        x, y, w, h,
        owner_user_id: userId,
        owner_alliance_id: allianceId,
        schedule,
        starts_at: starts_at ? new Date(starts_at) : null,
        ends_at: ends_at ? new Date(ends_at) : null
      });

      // 消耗广告位库存
      await UserInventory.consume(userId, sku_id, 1);

      res.json({
        success: true,
        message: '广告申请提交成功，等待审核',
        ad: {
          id: ad.id,
          status: ad.status,
          created_at: ad.created_at
        }
      });

    } catch (error) {
      console.error('提交广告失败:', error);
      res.status(500).json({
        success: false,
        message: '提交广告失败',
        error: error.message
      });
    }
  }

  // 获取用户的广告列表
  static async getUserAds(req, res) {
    try {
      const userId = req.user.id;
      const ads = await Ad.getByUser(userId);

      const adList = ads.map(ad => ({
        id: ad.id,
        pattern_id: ad.pattern_id,
        x: ad.x,
        y: ad.y,
        w: ad.w,
        h: ad.h,
        schedule: ad.schedule,
        status: ad.status,
        active: ad.active,
        starts_at: ad.starts_at,
        ends_at: ad.ends_at,
        created_at: ad.created_at,
        review_notes: ad.review_notes
      }));

      res.json({
        success: true,
        ads: adList
      });

    } catch (error) {
      console.error('获取用户广告失败:', error);
      res.status(500).json({
        success: false,
        message: '获取用户广告失败',
        error: error.message
      });
    }
  }

  // 获取活跃广告列表
  static async getActiveAds(req, res) {
    try {
      const ads = await Ad.getActiveAds();

      const activeAds = ads.map(ad => ({
        id: ad.id,
        pattern_id: ad.pattern_id,
        x: ad.x,
        y: ad.y,
        w: ad.w,
        h: ad.h,
        schedule: ad.schedule,
        starts_at: ad.starts_at,
        ends_at: ad.ends_at
      }));

      res.json({
        success: true,
        ads: activeAds
      });

    } catch (error) {
      console.error('获取活跃广告失败:', error);
      res.status(500).json({
        success: false,
        message: '获取活跃广告失败',
        error: error.message
      });
    }
  }

  // 获取区域内的广告
  static async getAdsByRegion(req, res) {
    try {
      const { x, y, w, h } = req.query;
      
      if (x === undefined || y === undefined || !w || !h) {
        return res.status(400).json({
          success: false,
          message: '缺少区域参数'
        });
      }

      const ads = await Ad.getByRegion(parseInt(x), parseInt(y), parseInt(w), parseInt(h));

      const regionAds = ads.map(ad => ({
        id: ad.id,
        pattern_id: ad.pattern_id,
        x: ad.x,
        y: ad.y,
        w: ad.w,
        h: ad.h,
        schedule: ad.schedule,
        starts_at: ad.starts_at,
        ends_at: ad.ends_at
      }));

      res.json({
        success: true,
        ads: regionAds
      });

    } catch (error) {
      console.error('获取区域广告失败:', error);
      res.status(500).json({
        success: false,
        message: '获取区域广告失败',
        error: error.message
      });
    }
  }

  // 管理员审核广告
  static async reviewAd(req, res) {
    try {
      const { adId } = req.params;
      const { status, notes } = req.body;

      if (!['approved', 'rejected'].includes(status)) {
        return res.status(400).json({
          success: false,
          message: '无效的审核状态'
        });
      }

      const ad = await Ad.getById(adId);
      if (!ad) {
        return res.status(404).json({
          success: false,
          message: '广告不存在'
        });
      }

      await ad.review(status, notes);

      res.json({
        success: true,
        message: '广告审核完成',
        ad: {
          id: ad.id,
          status: ad.status,
          review_notes: ad.review_notes
        }
      });

    } catch (error) {
      console.error('审核广告失败:', error);
      res.status(500).json({
        success: false,
        message: '审核广告失败',
        error: error.message
      });
    }
  }

  // 获取待审核广告列表（管理员）
  static async getPendingAds(req, res) {
    try {
      const ads = await Ad.getPendingAds();

      const pendingAds = ads.map(ad => ({
        id: ad.id,
        pattern_id: ad.pattern_id,
        x: ad.x,
        y: ad.y,
        w: ad.w,
        h: ad.h,
        schedule: ad.schedule,
        owner_user_id: ad.owner_user_id,
        owner_alliance_id: ad.owner_alliance_id,
        created_at: ad.created_at
      }));

      res.json({
        success: true,
        ads: pendingAds
      });

    } catch (error) {
      console.error('获取待审核广告失败:', error);
      res.status(500).json({
        success: false,
        message: '获取待审核广告失败',
        error: error.message
      });
    }
  }

  // 激活广告
  static async activateAd(req, res) {
    try {
      const { adId } = req.params;
      const ad = await Ad.getById(adId);

      if (!ad) {
        return res.status(404).json({
          success: false,
          message: '广告不存在'
        });
      }

      if (ad.status !== 'approved') {
        return res.status(400).json({
          success: false,
          message: '只能激活已审核通过的广告'
        });
      }

      await ad.activate();

      res.json({
        success: true,
        message: '广告激活成功',
        ad: {
          id: ad.id,
          active: ad.active
        }
      });

    } catch (error) {
      console.error('激活广告失败:', error);
      res.status(500).json({
        success: false,
        message: '激活广告失败',
        error: error.message
      });
    }
  }

  // 停用广告
  static async deactivateAd(req, res) {
    try {
      const { adId } = req.params;
      const ad = await Ad.getById(adId);

      if (!ad) {
        return res.status(404).json({
          success: false,
          message: '广告不存在'
        });
      }

      await ad.deactivate();

      res.json({
        success: true,
        message: '广告停用成功',
        ad: {
          id: ad.id,
          active: ad.active
        }
      });

    } catch (error) {
      console.error('停用广告失败:', error);
      res.status(500).json({
        success: false,
        message: '停用广告失败',
        error: error.message
      });
    }
  }

  // 检查广告是否应该播放
  static async checkAdPlayStatus(req, res) {
    try {
      const { adId } = req.params;
      const ad = await Ad.getById(adId);

      if (!ad) {
        return res.status(404).json({
          success: false,
          message: '广告不存在'
        });
      }

      const shouldPlay = ad.shouldPlay();
      const nextPlayTime = ad.getNextPlayTime();

      res.json({
        success: true,
        should_play: shouldPlay,
        next_play_time: nextPlayTime,
        ad: {
          id: ad.id,
          active: ad.active,
          status: ad.status,
          schedule: ad.schedule
        }
      });

    } catch (error) {
      console.error('检查广告播放状态失败:', error);
      res.status(500).json({
        success: false,
        message: '检查广告播放状态失败',
        error: error.message
      });
    }
  }
}

module.exports = AdController;
